package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";

    // Create LineItem instance using reflection since LineItem class is not found by compiler
    Class<?> lineItemClass = Class.forName("com.google.gson.examples.android.model.LineItem");
    Object lineItem = lineItemClass
        .getConstructor(String.class, int.class, long.class, String.class)
        .newInstance("itemName", 5, 10000L, expectedCurrencyCode);

    // Use reflection to access private field 'currencyCode'
    Field currencyCodeField = lineItemClass.getDeclaredField("currencyCode");
    currencyCodeField.setAccessible(true);
    String actualCurrencyCodeField = (String) currencyCodeField.get(lineItem);
    assertEquals(expectedCurrencyCode, actualCurrencyCodeField);

    // Invoke public getCurrencyCode() method via reflection
    String actualCurrencyCode = (String) lineItemClass.getMethod("getCurrencyCode").invoke(lineItem);
    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
